class RecordingLathe:
    def __init__(self, disc_material='lacquer'):
        self.disc_material = disc_material
        self.is_cutting = False

    def start_cutting(self):
        if not self.is_cutting:
            print(f"Starting groove cutting on {self.disc_material} disc...")
            self.is_cutting = True

    def modulate_groove(self, audio_signal):
        if self.is_cutting:
            print(f"Modulating groove with audio signal: {audio_signal[:20]}...")

    def stop_cutting(self):
        if self.is_cutting:
            print("Groove cutting complete.")
            self.is_cutting = False

# Example usage
lathe = RecordingLathe()
lathe.start_cutting()
audio_signal = "[simulated audio waveform data]"
lathe.modulate_groove(audio_signal)
lathe.stop_cutting()
